还有一个问题，我发现arxiv api的调用非常慢，因为还需要下载paper，有什么解决办法吗？以下是我的代码：
```python
class ArXivAPIWrapper(ArxivAPIWrapper):
    @model_validator(mode="before")
    @classmethod
    def validate_environment(cls, values: Dict) -> Any:
        """Validate that the python package exists in environment."""
        try:
            import arxiv

            class Search(arxiv.Search):
                def results(self, offset: int = 0) -> Generator[arxiv.Result, None, None]:
                    """
                    Executes the specified search using a default arXiv API client. For info
                    on default behavior, see `Client.__init__` and `Client.results`.
                    **Deprecated** after 2.0.0; use `Client.results`.
                    """
                    warnings.warn(
                        "The 'Search.results' method is deprecated, use 'Client.results' instead",
                        DeprecationWarning,
                        stacklevel=2,
                    )
                    return arxiv.Client(page_size=self.max_results).results(self, offset=offset)

            values["arxiv_search"] = Search
            values["arxiv_exceptions"] = (
                arxiv.ArxivError,
                arxiv.UnexpectedEmptyPageError,
                arxiv.HTTPError,
            )
            values["arxiv_result"] = arxiv.Result
        except ImportError:
            raise ImportError(
                "Could not import arxiv python package. "
                "Please install it with `pip install arxiv`."
            )
        return values

    def lazy_load(self, query: str) -> Iterator[Document]:
        """
        Run Arxiv search and get the article texts plus the article meta information.
        See https://lukasschwab.me/arxiv.py/index.html#Search
        Returns: documents with the document.page_content in text format
        Performs an arxiv search, downloads the top k results as PDFs, loads
        them as Documents, and returns them.
        Args:
            query: a plaintext search query
        """
        try:
            import fitz
        except ImportError:
            raise ImportError(
                "PyMuPDF package not found, please install it with "
                "`pip install pymupdf`"
            )
        try:
            # Remove the ":" and "-" from the query, as they can cause search problems
            # query = query.replace(":", "").replace("-", "")
            results = self._fetch_results(
                query
            )  # Using helper function to fetch results
        except self.arxiv_exceptions as ex:
            print("Error on arxiv: %s", ex)
            return
        for result in results:
            try:
                doc_file_name: str = result.download_pdf()
                with fitz.open(doc_file_name) as doc_file:
                    text: str = "".join(page.get_text() for page in doc_file)
            except (FileNotFoundError, fitz.fitz.FileDataError) as f_ex:
                print(f_ex)
                continue
            except Exception as e:
                if self.continue_on_failure:
                    print(e)
                    continue
                else:
                    raise e
            if self.load_all_available_meta:
                extra_metadata = {
                    "entry_id": result.entry_id,
                    "published_first_time": str(result.published.date()),
                    "comment": result.comment,
                    "journal_ref": result.journal_ref,
                    "doi": result.doi,
                    "primary_category": result.primary_category,
                    "categories": result.categories,
                    "links": [link.href for link in result.links],
                }
            else:
                extra_metadata = {}
            metadata = {
                "Published": str(result.updated.date()),
                "Title": result.title,
                "Authors": ", ".join(a.name for a in result.authors),
                "Summary": result.summary,
                **extra_metadata,
            }
            yield Document(
                page_content=text[: self.doc_content_chars_max], metadata=metadata
            )
            os.remove(doc_file_name)

class ArXivLoader(ArxivLoader):
    def __init__(
        self, query: str, doc_content_chars_max: Optional[int] = None, **kwargs: Any
    ):
        """Initialize with search query to find documents in the Arxiv.
        Supports all arguments of `ArxivAPIWrapper`.
        Args:
            query: free text which used to find documents in the Arxiv
            doc_content_chars_max: cut limit for the length of a document's content
        """  # noqa: E501
        self.query = query
        self.client = ArXivAPIWrapper(
            doc_content_chars_max=doc_content_chars_max, **kwargs
        )
